PROCEDURE CalculateImpact(disposal_method, weight)
BEGIN
 // Impact factors (normalized 0-10, higher = worse)
 SET air_pollution_factor = {
 'landfill': 3, 'incineration': 8, 'informal_recycling': 9, 'formal_recycling': 2
 }
 SET water_pollution_factor = {
 'landfill': 7, 'incineration': 3, 'informal_recycling': 9, 'formal_recycling': 1
 }
 SET soil_pollution_factor = {
 'landfill': 6, 'incineration': 2, 'informal_recycling': 10, 'formal_recycling': 1
 }
 SET health_risk_factor = {
 'landfill': 4, 'incineration': 5, 'informal_recycling': 10, 'formal_recycling': 2
 }

 // Calculate composite score
 impact_score = (
 air_pollution_factor[disposal_method] +
 water_pollution_factor[disposal_method] +
 soil_pollution_factor[disposal_method] +
 health_risk_factor[disposal_method]
 ) * weight / 1000

 // Determine recommendation
 IF impact_score < 2 THEN
 recommendation = "RECOMMENDED: Formal recycling"
 ELSE IF impact_score < 5 THEN
 recommendation = "MODERATE: Controlled landfill"
 ELSE IF impact_score < 8 THEN
 recommendation = "CAUTION: Incineration with energy recovery"
 ELSE
 recommendation = "AVOID: Informal disposal"
 END IF

 RETURN {score: impact_score, recommendation: recommendation}
END
